sub generate_session_id {
    my @chars = ('A'..'Z', 'a'..'z', '0'..'9');
    my $session_id = '';
    for (1..64) {
        $session_id .= $chars[int(rand(@chars))];
    }
    return sha256_hex($session_id . time() . $$);
}

sub html_escape {
    my ($text) = @_;
    $text =~ s/&/&amp;/g;
    $text =~ s/</&lt;/g;
    $text =~ s/>/&gt;/g;
    $text =~ s/"/&quot;/g;
    $text =~ s/'/&#39;/g;
    return $text;
}